@require_POST
def saml_acs(request):
    """
    Assertion Consumer Service (ACS) endpoint.
    Handles SAML POST responses from the Identity Provider.
    """
    if 'SAMLResponse' not in request.POST:
        logger.error("SAMLResponse not found in POST data.")
        return render(request, 'saml_error.html', {'error': 'Invalid SAML response.'}, status=400)

    saml_response_b64 = request.POST['SAMLResponse']

    try:
        processor = SAMLResponseProcessor(saml_response_b64)
        name_id, saml_attributes, session_index = processor.process()

        if not name_id:
            logger.error("SAML Response missing NameID.")
            return render(request, 'saml_error.html', {'error': 'Missing NameID in SAML Assertion.'}, status=400)

        # Map SAML attributes to Django user model fields
        user_data = {}
        attribute_mapping = getattr(settings, 'SAML_SP_CONFIG', {}).get('ATTRIBUTE_MAPPING', {})
        for saml_attr, django_field in attribute_mapping.items():
            if saml_attr in saml_attributes:
                user_data[django_field] = saml_attributes[saml_attr]

        # Determine username
        username = name_id # Default to NameID
        default_username_attr = getattr(settings, 'SAML_SP_CONFIG', {}).get('DEFAULT_USERNAME_ATTRIBUTE')
        if default_username_attr and default_username_attr in saml_attributes:
            username = saml_attributes[default_username_attr]
        
        # Ensure username is valid for Django (e.g., no @ symbols if not an email field)
        # You might need to sanitize or slugify usernames depending on your IDP
        if '@' in username and len(username) > 150: # Adjust length based on Django's max_length
            logger.warning(f"Username derived from SAML is an email and too long: {username}. Truncating.")
            # Example truncation, consider if this is appropriate for your system
            username = username[:150]

        # Try to find an existing user or create a new one
        try:
            user = User.objects.get(username=username)
            logger.info(f"Existing user '{username}' found.")
            # Update user attributes if necessary
            for field, value in user_data.items():
                setattr(user, field, value)
            user.save()
        except User.DoesNotExist:
            logger.info(f"User '{username}' does not exist, creating new user.")
            user = User.objects.create_user(username=username, **user_data)
            user.save()

        # Create Django session
        user.backend = 'django.contrib.auth.backends.ModelBackend' # Required for authenticate/login
        login(request, user)
        logger.info(f"User '{username}' logged in successfully via SAML.")

        # Store SAML session_index for logout purposes (optional but good for SLO)
        if session_index:
            request.session['saml_session_index'] = session_index
            request.session['saml_name_id'] = name_id # Also store name_id for SLO

        return redirect(getattr(settings, 'LOGIN_REDIRECT_URL', '/'))

    except ValueError as e:
        logger.error(f"SAML processing error: {e}", exc_info=True)
        return render(request, 'saml_error.html', {'error': f"SAML processing error: {e}"}, status=400)
    except Exception as e:
        logger.exception(f"An unexpected error occurred during SAML ACS: {e}")
        return render(request, 'saml_error.html', {'error': f"An unexpected error occurred: {e}"}, status=500)


def saml_metadata(request):
    """
    Generates the SAML Service Provider (SP) metadata XML.
    This XML is provided to the Identity Provider (IDP).
    """
    config = getattr(settings, 'SAML_SP_CONFIG', {})
    entity_id = config.get('ENTITY_ID', 'http://localhost:8000/saml/metadata/')
    acs_url = config.get('ACS_URL', 'http://localhost:8000/saml/acs/')
    sp_cert = config.get('SP_CERT', '') # You should generate a self-signed cert for your SP

    metadata_template = """<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     validUntil="2030-01-01T00:00:00Z"
                     cacheDuration="PT604800S"
                     entityID="{entity_id}">
    <md:SPSSODescriptor AuthnRequestsSigned="false" WantAssertionsSigned="true" protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        {signing_cert}
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                     Location="{acs_url}"
                                     index="1"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""

    signing_cert_xml = ""
    if sp_cert:
        # Remove BEGIN/END tags and newlines
        clean_cert = "".join(sp_cert.splitlines()[1:-1])
        signing_cert_xml = f"""
        <md:KeyDescriptor use="signing">
            <ds:KeyInfo xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
                <ds:X509Data>
                    <ds:X509Certificate>{clean_cert}</ds:X509Certificate>
                </ds:X509Data>
            </ds:KeyInfo>
        </md:KeyDescriptor>
        """

    metadata = metadata_template.format(
        entity_id=entity_id,
        acs_url=acs_url,
        signing_cert=signing_cert_xml
    )
    return render(request, 'saml_metadata.xml', {'metadata': metadata}, content_type='application/xml')


